import { AnimVBase, KeyFrame, KeyFrameType, Point, Tween, Color, AudioEvent, Event } from '../DataFormats';
export interface EyeTextureKF extends KeyFrameType {
    Texture: string;
    Color: Color;
}
export interface EventKF extends KeyFrameType {
    Event: Event;
}
export interface EyeKF extends KeyFrameType {
    Rotate: number;
    Scale: Point;
    Translate: Point;
    Tween: Tween;
    'Vertex 1': Point;
    'Vertex 2': Point;
    'Vertex 3': Point;
    'Vertex 4': Point;
    'Vertex 5': Point;
    'Vertex 6': Point;
    'Vertex 7': Point;
    'Vertex 8': Point;
    'Vertex 9': Point;
}
export interface TextureKF extends KeyFrameType {
    Texture: string;
    Color: Color;
}
export interface BodyKF extends KeyFrameType {
    Head: number;
    Torso: number;
    Pelvis: number;
    Tween: Tween;
}
export interface AudioEventKF extends KeyFrameType {
    AudioEvent: AudioEvent;
}
export interface Layer<Type extends KeyFrameType> {
    id: string;
    name: string;
    type: string;
    locked: boolean;
    visible: boolean;
    keyframes: Array<KeyFrame<Type>>;
}
/**
 * @typedef jibo.animdb#Anim
 * @description Interface for animation formats
 * @property version {string} Keys file version.
 * @property framerate {number} Framerate of keys file.
 * @property duration {number} Duration of keys file.
 * @property scale {number} Scale of keys file.
 * @property layers {jibo.animdb.LayerName[]} Layers included in the animation.
 * @property [animdb] {Object} Animation meta data for animations that are part of the database.
 */
export interface Anim extends AnimVBase {
    version: string;
    framerate: number;
    duration: number;
    scale: number;
    layers: Array<Layer<any>>;
    animdb?: any;
}
